// Solar-surplus heater FSM. Reads HA state from the global context populated
// by node-red-contrib-home-assistant-websocket. Pure function over current HA
// state + flow-context FSM state.

const ha = global.get('homeassistant')?.homeAssistant?.states;
if (!ha) {
    node.warn('HA global state unavailable. In server config, enable "Include in Home Assistant"/"Expose to Node-RED" so global.homeassistant is populated.');
    return null;
}

const num = (id, def) => {
    const s = ha[id]?.state;
    const n = parseFloat(s);
    return isNaN(n) ? def : n;
};
const isOn = (id) => ha[id]?.state === 'on';
const attrNum = (id, key, def) => {
    const v = ha[id]?.attributes?.[key];
    const n = parseFloat(v);
    return isNaN(n) ? def : n;
};

// --- BMS / environment ---
const soc = num('sensor.jk_pb_bms_state_of_charge', NaN);
const chgP = num('sensor.jk_pb_bms_charging_power', 0);
const dchgP = num('sensor.jk_pb_bms_discharging_power', 0);
const charging = isOn('binary_sensor.jk_pb_bms_charging');
const discharging = isOn('binary_sensor.jk_pb_bms_discharging');
const online = isOn('binary_sensor.jk_pb_bms_online_status');
const sunElev = attrNum('sun.sun', 'elevation', -90);

// --- Tunables (HA helpers) ---
const socFloor = num('input_number.heater_soc_floor', 85);
const sunMin = num('input_number.heater_sun_elevation_min', 15);
const probeSec = num('input_number.heater_probe_seconds', 30);
const backoffMin = num('input_number.heater_backoff_minutes', 5);
const dischgTh = num('input_number.heater_discharge_threshold_w', 50);

// --- FSM state ---
const now = Date.now();
let state = flow.get('heater_state') || 'idle';
let since = flow.get('heater_state_since') || now;

const setState = (s) => {
    if (state !== s) {
        node.log(`heater FSM: ${state} -> ${s} | soc=${soc}% chgP=${chgP}W dchgP=${dchgP}W sunElev=${sunElev.toFixed(1)}°`);
        state = s;
        since = now;
    }
};

const sunOK = sunElev >= sunMin;
const socOK = !isNaN(soc) && soc >= socFloor;
const heavyDraw = discharging && dchgP > dischgTh;

if (!online) {
    // BMS link lost — drop heater, idle
    setState('idle');
} else {
    switch (state) {
        case 'idle':
            if (sunOK && socOK && charging && chgP > 0) setState('probe');
            break;
        case 'probe':
            if (!sunOK || !socOK) setState('idle');
            else if (heavyDraw) setState('backoff');
            else if (now - since >= probeSec * 1000) setState('run');
            break;
        case 'run':
            if (!sunOK || !socOK) setState('idle');
            else if (heavyDraw) setState('backoff');
            break;
        case 'backoff':
            if (now - since >= backoffMin * 60 * 1000) setState('idle');
            break;
        default:
            setState('idle');
    }
}

flow.set('heater_state', state);
flow.set('heater_state_since', since);

const wantOn = (state === 'probe' || state === 'run');

node.status({
    fill: state === 'run' ? 'green' : state === 'probe' ? 'yellow' : state === 'backoff' ? 'red' : 'grey',
    shape: 'dot',
    text: `${state} | soc=${isNaN(soc) ? '?' : soc + '%'} chg=${chgP}W dchg=${dchgP}W sun=${sunElev.toFixed(0)}°`
});

return [
    { topic: 'heater', payload: wantOn ? 'on' : 'off' },
    { topic: 'state', payload: state }
];
